const PROCESSING_FEE_G = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE_G = 60;
const COMPONENT_UNIT_PRICE_G = 25;

const MAIN_ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; cursed?: boolean };
type Scenario = {
  steps: Array<{ op: "quote"; items: Item[] }>;
};

const componentBaseForGroup = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;

const componentBaseTotal = (items: Item[]): number => {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  return [...counts.values()]
    .map(componentBaseForGroup)
    .reduce((sum, n) => sum + n, 0);
};

const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;

const mainItemPremium = (item: Item): number => {
  const base = mainItemBase(item);
  const curseSurcharge = item.cursed ? base * 0.5 : 0;
  return base + curseSurcharge;
};

const applyFirstInsuranceSurcharge = (policyBase: number): number =>
  policyBase / 10;

const quotePremium = (items: Item[]): number => {
  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const policyBase =
    mainItems.map(mainItemBase).reduce((sum, n) => sum + n, 0) +
    componentBaseTotal(items);
  const itemPremiumsTotal =
    mainItems.map(mainItemPremium).reduce((sum, n) => sum + n, 0) +
    componentBaseTotal(items);
  return Math.ceil(
    itemPremiumsTotal + applyFirstInsuranceSurcharge(policyBase) + PROCESSING_FEE_G,
  );
};

export const runScenario = (scenario: unknown): unknown => {
  const items = (scenario as Scenario).steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};
